#ab-wrap{background:linear-gradient(180deg,rgba(40,32,20,.95),rgba(25,20,12,.98));border:2px solid #5a4a32;border-radius:6px;padding:5px 8px;display:flex;gap:3px;box-shadow:0 -2px 15px rgba(0,0,0,.5)}
